import React, { useState, useEffect, useCallback } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import TrustBadge from '../components/TrustBadge';
import './SupportCampaignPage.css';

const PRESET_AMOUNTS = [100, 500, 1000, 2500];

const SupportCampaignPage = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user, isAuthenticated } = useAuth();

  const [supportCampaign, setSupportCampaign] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [donateAmount, setDonateAmount] = useState('');
  const [donateError, setDonateError] = useState('');
  const [donateLoading, setDonateLoading] = useState(false);
  const [donateSuccess, setDonateSuccess] = useState('');

  const fetchSupportCampaign = useCallback(async () => {
    try {
      setLoading(true);
      const { data } = await axios.get(`/api/support-campaigns/detail/${id}`);
      setSupportCampaign(data.supportCampaign);
    } catch (err) {
      setError(err.response?.status === 404 ? 'Support campaign not found.' : err.response?.data?.message || 'Failed to load.');
    } finally {
      setLoading(false);
    }
  }, [id]);

  useEffect(() => { fetchSupportCampaign(); }, [fetchSupportCampaign]);

  const handleDonate = async () => {
    if (!isAuthenticated()) { navigate('/login'); return; }
    const amount = Number(donateAmount);
    if (!donateAmount || isNaN(amount) || amount < 1) {
      setDonateError('Please enter a valid amount.'); return;
    }

    try {
      setDonateLoading(true);
      setDonateError('');
      setDonateSuccess('');

      const parentId = supportCampaign.parentCampaign?._id;
      const { data: orderData } = await axios.post('/api/donations/create-order', {
        amount,
        campaignId: parentId
      });

      const razorpayKey = process.env.REACT_APP_RAZORPAY_KEY || orderData.key;

      if (typeof window.Razorpay === 'undefined') {
        throw new Error('Razorpay failed to load. Please refresh.');
      }

      const options = {
        key: razorpayKey,
        amount: orderData.amount,
        currency: orderData.currency,
        name: 'FundIt',
        description: `Support campaign: ${supportCampaign.title}`,
        order_id: orderData.orderId,
        prefill: { name: user.name, email: user.email },
        theme: { color: '#1a56db' },
        handler: async (response) => {
          try {
            await axios.post('/api/donations/record', {
              campaignId: parentId,
              amount,
              paymentId: response.razorpay_payment_id,
              orderId: response.razorpay_order_id,
              message: `Via support campaign: ${supportCampaign.title}`
            });
            // Also increment support campaign raised
            // This is tracked via the parent campaign donation
            setDonateSuccess(`­¤Äē Thank you! Ōé╣${amount.toLocaleString('en-IN')} donated via this support campaign.`);
            setDonateAmount('');
            fetchSupportCampaign();
          } catch {
            setDonateError('Payment succeeded but recording failed. Contact support.');
          } finally {
            setDonateLoading(false);
          }
        },
        modal: {
          ondismiss: () => {
            setDonateLoading(false);
            setDonateError('Payment cancelled.');
          }
        }
      };

      const rzp = new window.Razorpay(options);
      rzp.on('payment.failed', (response) => {
        setDonateLoading(false);
        setDonateError(`Payment failed: ${response.error.description || 'Unknown error.'}`);
      });
      rzp.open();
    } catch (err) {
      setDonateLoading(false);
      setDonateError(err.response?.data?.message || err.message || 'Payment failed.');
    }
  };

  if (loading) {
    return (
      <div className="loading-state" style={{ minHeight: '60vh' }}>
        <div className="spinner spinner-lg" />
        <p>Loading support campaign...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container" style={{ paddingTop: '4rem', textAlign: 'center' }}>
        <div className="alert alert-error" style={{ maxWidth: '500px', margin: '0 auto 1.5rem' }}>
          <span>ŌÜĀ’ĖÅ</span><p>{error}</p>
        </div>
        <Link to="/" className="btn btn-primary">ŌåÉ Back to Campaigns</Link>
      </div>
    );
  }

  const parent = supportCampaign.parentCampaign;
  const progress = Math.min(Math.round((supportCampaign.raised / supportCampaign.goal) * 100), 100);

  return (
    <div className="support-page">
      <div className="container">

        {/* Parent campaign link */}
        <div className="support-parent-banner" id="support-parent-banner">
          <span>­¤öŚ This is a support campaign for:</span>
          {parent?._id
            ? <Link to={`/campaigns/${parent._id}`} className="parent-link">{parent.title}</Link>
            : <span>{parent?.title || 'Parent Campaign'}</span>
          }
          {parent && <TrustBadge score={parent.trustScore || 0} size="sm" />}
        </div>

        <div className="support-layout">

          {/* Main */}
          <div className="support-main">
            <div className="support-card" id="support-detail-card">
              <div className="support-creator-row">
                <div className="support-avatar">
                  {(supportCampaign.creator?.name || 'A').charAt(0).toUpperCase()}
                </div>
                <div>
                  <div className="support-creator-name">{supportCampaign.creator?.name || 'Supporter'}</div>
                  <div className="support-creator-label">is raising funds for this campaign</div>
                </div>
              </div>

              <h1 className="support-title" id="support-campaign-title">{supportCampaign.title}</h1>

              <div className="support-progress-section">
                <div className="support-raised">
                  Ōé╣{supportCampaign.raised.toLocaleString('en-IN')}
                  <span className="support-goal-label"> of Ōé╣{supportCampaign.goal.toLocaleString('en-IN')} goal</span>
                </div>
                <div className="progress-bar-wrapper" style={{ height: '10px', margin: '0.75rem 0' }}>
                  <div className="progress-bar-fill" style={{ width: `${progress}%` }} />
                </div>
                <div className="support-pct">{progress}% funded</div>
              </div>

              <div className="support-share-section">
                <p className="support-share-text">­¤ōŻ Help {supportCampaign.creator?.name?.split(' ')[0] || 'this supporter'} reach their goal:</p>
                <div className="support-share-buttons">
                  <button
                    className="btn btn-wa"
                    id="btn-support-wa"
                    onClick={() => {
                      const text = encodeURIComponent(`­¤ÆÖ I'm fundraising for "${parent?.title}". Support my campaign on FundIt: ${window.location.href}`);
                      window.open(`https://wa.me/?text=${text}`, '_blank', 'noopener,noreferrer');
                    }}
                  >
                    ­¤ō▒ Share on WhatsApp
                  </button>
                  <button
                    className="btn btn-copy"
                    id="btn-support-copy"
                    onClick={() => {
                      navigator.clipboard.writeText(window.location.href);
                      alert('Link copied!');
                    }}
                  >
                    ­¤öŚ Copy Link
                  </button>
                </div>
              </div>
            </div>
          </div>

          {/* Donate Sidebar */}
          <div className="support-sidebar">
            <div className="support-donate-card" id="support-donate-card">
              <h3>­¤ÆÖ Support This Campaign</h3>

              {donateSuccess && (
                <div className="alert alert-success"><span>­¤Äē</span><p>{donateSuccess}</p></div>
              )}
              {donateError && (
                <div className="alert alert-error"><span>ŌÜĀ’ĖÅ</span><p>{donateError}</p></div>
              )}

              {!isAuthenticated() ? (
                <Link to="/login" className="btn btn-primary" style={{ display: 'block', textAlign: 'center' }}>
                  ­¤öÉ Sign In to Donate
                </Link>
              ) : (
                <>
                  <div className="preset-grid" id="support-preset-amounts">
                    {PRESET_AMOUNTS.map((amt) => (
                      <button
                        key={amt}
                        className={`preset-btn ${donateAmount === String(amt) ? 'preset-btn-active' : ''}`}
                        onClick={() => { setDonateAmount(String(amt)); setDonateError(''); }}
                      >
                        Ōé╣{amt.toLocaleString('en-IN')}
                      </button>
                    ))}
                  </div>
                  <div className="amount-input-wrapper" style={{ marginTop: '0.75rem' }}>
                    <span className="amount-prefix">Ōé╣</span>
                    <input
                      id="support-amount-input"
                      type="number"
                      className="amount-input"
                      placeholder="Custom amount"
                      value={donateAmount}
                      onChange={(e) => { setDonateAmount(e.target.value); setDonateError(''); }}
                      min={1}
                    />
                  </div>
                  <button
                    className="donate-cta-btn"
                    id="btn-support-donate"
                    onClick={handleDonate}
                    disabled={donateLoading || !donateAmount || Number(donateAmount) < 1}
                    style={{ marginTop: '1rem' }}
                  >
                    {donateLoading ? <><span className="spinner" /> Processing...</> : '­¤ÆÜ Donate via Razorpay'}
                  </button>
                </>
              )}
            </div>

            <div className="support-back-link">
              {parent?._id && (
                <Link to={`/campaigns/${parent._id}`} className="btn btn-secondary" style={{ width: '100%', textAlign: 'center' }}>
                  ŌåÉ View Main Campaign
                </Link>
              )}
            </div>
          </div>

        </div>
      </div>
    </div>
  );
};

export default SupportCampaignPage;
